function PageHero({ title, subtitle, img, gradient, minH }) {
  const bg = img ? `url(${img})` : (gradient || `linear-gradient(135deg, ${T.bg}, hsl(38,40%,18%), hsl(178,25%,16%))`);
  return (<div style={{ position: "relative", minHeight: minH || 220, display: "flex", flexDirection: "column", justifyContent: "flex-end", padding: "24px 20px 20px", overflow: "hidden" }}><div style={{ position: "absolute", inset: 0, background: bg, backgroundSize: "cover", backgroundPosition: "center", filter: img ? "brightness(0.8)" : "none" }} /><div style={{ position: "absolute", inset: 0, background: "linear-gradient(to bottom, rgba(0,0,0,0.10) 0%, rgba(0,0,0,0.03) 50%, rgba(0,0,0,0.30) 100%)" }} /><div style={{ position: "relative", zIndex: 1, color: "#fff" }}><h1 style={{ fontFamily: DF, fontSize: "3.5rem", margin: "0 0 4px", lineHeight: 1.05, fontWeight: 700 }}>{title}</h1>{subtitle && <p style={{ fontSize: 14, color: "rgba(255,255,255,0.85)", margin: 0, lineHeight: 1.4, maxWidth: "95%" }}>{subtitle}</p>}</div></div>);
}

function SH({ title, linkText, linkPage }) { const { setPage } = useContext(AppContext); return (<div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}><h2 style={{ fontFamily: DF, fontSize: 22, color: T.text, margin: 0, fontWeight: 700 }}>{title}</h2>{linkText && <button onClick={() => setPage(linkPage)} style={{ fontSize: 13, fontWeight: 600, color: T.accent, background: "none", border: "none", cursor: "pointer", display: "flex", alignItems: "center", gap: 4 }}>{linkText} <ChevronRight size={14} /></button>}</div>); }
function SB({ label, value }) { return (<div style={{ background: T.bgDim, borderRadius: 10, padding: "12px 14px", textAlign: "center" }}><div style={{ fontFamily: DF, fontSize: 22, color: T.text, fontWeight: 700 }}>{value}</div><div style={{ fontSize: 11, color: T.textMuted, fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.05em", marginTop: 2 }}>{label}</div></div>); }
function LocBadge({ loc }) { const colors = { NW: T.accent, DIV: T.success, SEL: "#8b5cf6" }; const c = colors[(loc || "").toUpperCase()] || T.textMuted; return <span style={{ fontSize: 10, fontWeight: 700, padding: "2px 6px", borderRadius: 4, background: `${c}15`, color: c }}>{(loc || "").toUpperCase()}</span>; }
function IF({ label, value, onChange, placeholder, multiline }) { const s = { width: "100%", padding: "10px 14px", background: T.bgDim, border: `1px solid ${T.border}`, borderRadius: 8, color: T.text, fontSize: 13, fontFamily: "'DM Sans', system-ui, sans-serif", outline: "none", boxSizing: "border-box", resize: "none" }; return (<div><label style={{ display: "block", fontSize: 12, fontWeight: 600, color: T.textMuted, marginBottom: 6, textTransform: "uppercase", letterSpacing: "0.05em" }}>{label}</label>{multiline ? <textarea rows={3} value={value} onChange={e => onChange(e.target.value)} placeholder={placeholder} style={s} /> : <input value={value} onChange={e => onChange(e.target.value)} placeholder={placeholder} style={s} />}</div>); }

function PCard({ practice: p, expanded, onToggle }) {
  const isToday = p.date === today, isFuture = p.date > today;
  return (<div style={{ background: T.bgCard, border: `1px solid ${isToday ? T.accentBorder : T.border}`, borderRadius: 14, overflow: "hidden", cursor: "pointer" }} onClick={onToggle}><div style={{ padding: "16px 18px" }}><div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 8 }}><div><div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 4, flexWrap: "wrap" }}>{isToday && <span style={{ fontSize: 10, fontWeight: 700, textTransform: "uppercase", padding: "2px 8px", borderRadius: 4, background: T.accentGhost, color: T.accent }}>Today</span>}{isFuture && <span style={{ fontSize: 10, fontWeight: 700, textTransform: "uppercase", padding: "2px 8px", borderRadius: 4, background: T.successGhost, color: T.success }}>Upcoming</span>}<span style={{ fontSize: 10, fontWeight: 700, textTransform: "uppercase", padding: "2px 8px", borderRadius: 4, background: T.bgDim, color: T.textMuted }}>{p.type}</span>{p.location && <LocBadge loc={p.location} />}</div><h3 style={{ fontFamily: DF, fontSize: 20, margin: 0, color: T.text, fontWeight: 700 }}>{p.name}</h3></div><ChevronDown size={18} color={T.textFaint} style={{ transform: expanded ? "rotate(180deg)" : "none", transition: "transform 0.2s", flexShrink: 0, marginTop: 4 }} /></div><div style={{ display: "flex", alignItems: "center", gap: 12, fontSize: 12, color: T.textMuted, flexWrap: "wrap" }}><span>{fmtDS(p.date)}</span><span style={{ display: "flex", alignItems: "center", gap: 3 }}><Clock size={12} /> {p.duration} min</span><span>{p.style}</span></div></div>{expanded && (<div style={{ padding: "0 18px 18px", borderTop: `1px solid ${T.borderLight}`, paddingTop: 14 }}><p style={{ fontSize: 13, color: "#5a5040", lineHeight: 1.6, margin: "0 0 12px" }}>{p.description}</p>{p.intention && <div style={{ padding: "10px 14px", borderRadius: 10, background: `linear-gradient(135deg, ${T.accentGhost}, transparent)`, border: `1px solid ${T.accentBorder}`, marginBottom: 10 }}><p style={{ fontSize: 11, fontWeight: 700, textTransform: "uppercase", color: T.accent, margin: "0 0 4px", letterSpacing: "0.05em" }}>Intention</p><p style={{ fontSize: 13, color: T.text, fontStyle: "italic", margin: 0, lineHeight: 1.5 }}>{p.intention}</p></div>}{p.teacherTip && <div style={{ padding: "10px 14px", borderRadius: 10, background: T.bgDim }}><p style={{ fontSize: 11, fontWeight: 700, textTransform: "uppercase", color: T.textMuted, margin: "0 0 4px", letterSpacing: "0.05em" }}>Teacher Tip</p><p style={{ fontSize: 13, color: "#5a5040", margin: 0, lineHeight: 1.5 }}>{p.teacherTip}</p></div>}</div>)}</div>);
}

function CTACard() { return (<div style={{ background: `linear-gradient(135deg, ${T.bg}, hsl(38,30%,18%))`, borderRadius: 16, padding: "24px 20px", color: "#fff", position: "relative", overflow: "hidden" }}><div style={{ position: "absolute", top: -20, right: -20, width: 100, height: 100, borderRadius: "50%", background: `${T.accent}15` }} /><Sparkles size={28} color={T.accent} style={{ marginBottom: 12 }} /><h3 style={{ fontFamily: DF, fontSize: 22, margin: "0 0 6px", fontWeight: 700 }}>2 Weeks for $40</h3><p style={{ fontSize: 13, color: "#b8a898", margin: "0 0 16px", lineHeight: 1.5 }}>New to NOW? Unlimited classes at all three locations. All styles, all levels. Your mat is waiting.</p><button style={{ padding: "12px 24px", borderRadius: 8, border: "none", fontSize: 15, fontWeight: 700, cursor: "pointer", fontFamily: DF, background: T.accent, color: "#fff" }}>Start Now</button></div>); }
function AC({ title, children }) { return (<div style={{ background: "#fff", border: "1px solid #e5e7eb", borderRadius: 12, padding: 18 }}><h3 style={{ fontSize: 15, fontWeight: 700, color: "#111827", margin: "0 0 14px" }}>{title}</h3>{children}</div>); }

// === MODALS ===
function SettingsModal({ onClose }) { return (<div onClick={onClose} style={{ position: "absolute", inset: 0, background: "rgba(0,0,0,.5)", backdropFilter: "blur(4px)", zIndex: 50, display: "flex", alignItems: "flex-end", justifyContent: "center" }}><div onClick={e => e.stopPropagation()} style={{ width: "100%", maxWidth: 390, background: T.bgCard, borderRadius: "20px 20px 0 0", padding: "20px 20px 32px", maxHeight: "80vh", overflow: "auto" }}><div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}><h2 style={{ fontFamily: DF, fontSize: 24, margin: 0, fontWeight: 700 }}>Settings</h2><button onClick={onClose} style={{ padding: 4, borderRadius: 8, border: "none", background: "transparent", cursor: "pointer" }}><X size={20} color={T.textMuted} /></button></div><div style={{ display: "flex", flexDirection: "column", gap: 10 }}>{SC.locations.map(loc => (<div key={loc.id} style={{ display: "flex", alignItems: "center", gap: 14, padding: "14px 16px", background: T.bgDim, borderRadius: 12 }}><MapPin size={20} color={T.accent} /><div><p style={{ fontWeight: 600, fontSize: 14, margin: 0, color: T.text }}>{loc.name}</p><p style={{ fontSize: 12, color: T.textMuted, margin: "2px 0 0" }}>{loc.address}</p></div></div>))}{[{ icon: Share2, label: SC.social.instagram, sub: "Follow us on Instagram" }, { icon: Gift, label: "NOW Points", sub: "Earn points with every class" }, { icon: Heart, label: "Community Scholarships", sub: "BIPOC, LGBTQIA+, and underrepresented communities" }].map((item, i) => (<div key={i} style={{ display: "flex", alignItems: "center", gap: 14, padding: "14px 16px", background: T.bgDim, borderRadius: 12 }}><item.icon size={20} color={T.accent} /><div><p style={{ fontWeight: 600, fontSize: 14, margin: 0, color: T.text }}>{item.label}</p><p style={{ fontSize: 12, color: T.textMuted, margin: "2px 0 0" }}>{item.sub}</p></div></div>))}</div></div></div>); }

function NotificationsModal({ onClose }) { const ns = [{ id: "n1", title: "Class Confirmed", message: "Power Vinyasa at 7:00 AM tomorrow at N Williams with Jamie.", time: "2h ago", read: false }, { id: "n2", title: "NOW Points Earned", message: "You earned 20 NOW Points. 30 points to your next guest pass.", time: "1d ago", read: false }, { id: "n3", title: "Sauna + Cold Plunge Almost Full", message: "May 3 at Sellwood Riverfront. Only 2 spots remaining.", time: "2d ago", read: true }, { id: "n4", title: "200hr Teacher Training", message: "Winter 2026 cohort has 4 spots left. Apply today.", time: "4d ago", read: true }]; return (<div onClick={onClose} style={{ position: "absolute", inset: 0, background: "rgba(0,0,0,.5)", backdropFilter: "blur(4px)", zIndex: 50, display: "flex", alignItems: "flex-end", justifyContent: "center" }}><div onClick={e => e.stopPropagation()} style={{ width: "100%", maxWidth: 390, background: T.bgCard, borderRadius: "20px 20px 0 0", padding: "20px 20px 32px", maxHeight: "80vh", overflow: "auto" }}><div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}><h2 style={{ fontFamily: DF, fontSize: 24, margin: 0, fontWeight: 700 }}>Notifications</h2><button onClick={onClose} style={{ padding: 4, borderRadius: 8, border: "none", background: "transparent", cursor: "pointer" }}><X size={20} color={T.textMuted} /></button></div><div style={{ display: "flex", flexDirection: "column", gap: 8 }}>{ns.map(n => (<div key={n.id} style={{ padding: "14px 16px", borderRadius: 12, background: n.read ? T.bgDim : T.accentGhost, border: `1px solid ${n.read ? T.border : T.accentBorder}` }}><div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}><h4 style={{ fontSize: 14, fontWeight: 700, margin: "0 0 4px", color: T.text }}>{n.title}</h4>{!n.read && <div style={{ width: 8, height: 8, borderRadius: "50%", background: T.accent, flexShrink: 0, marginTop: 4 }} />}</div><p style={{ fontSize: 13, color: "#5a5040", margin: "0 0 4px", lineHeight: 1.4 }}>{n.message}</p><p style={{ fontSize: 11, color: T.textFaint, margin: 0 }}>{n.time}</p></div>))}</div></div></div>); }

function ReservationModal({ classData, onConfirm, onClose }) { const [confirmed, setConfirmed] = useState(false); const isFull = classData.registered >= classData.capacity; const doConfirm = () => { onConfirm(classData.id); setConfirmed(true); setTimeout(onClose, 1500); }; return (<div onClick={onClose} style={{ position: "absolute", inset: 0, background: "rgba(0,0,0,.5)", backdropFilter: "blur(4px)", zIndex: 50, display: "flex", alignItems: "center", justifyContent: "center" }}><div onClick={e => e.stopPropagation()} style={{ width: "90%", maxWidth: 340, background: T.bgCard, borderRadius: 18, padding: "24px 22px", boxShadow: "0 12px 40px rgba(0,0,0,.2)" }}>{confirmed ? (<div style={{ textAlign: "center", padding: "20px 0" }}><div style={{ width: 56, height: 56, borderRadius: "50%", background: T.accentGhost, display: "flex", alignItems: "center", justifyContent: "center", margin: "0 auto 12px" }}><Check size={28} color={T.accent} /></div><h3 style={{ fontFamily: DF, fontSize: 22, margin: "0 0 6px", fontWeight: 700 }}>{isFull ? "Added to Waitlist" : "You're In!"}</h3><p style={{ fontSize: 13, color: T.textMuted, margin: 0 }}>See you on the mat</p></div>) : (<><h3 style={{ fontFamily: DF, fontSize: 22, margin: "0 0 4px", color: T.text, fontWeight: 700 }}>Reserve Your Spot</h3><p style={{ fontSize: 13, color: T.textMuted, margin: "0 0 16px" }}>{classData.dayLabel || fmtDS(today)}</p><div style={{ display: "flex", flexDirection: "column", gap: 10, marginBottom: 20 }}>{[["Class", classData.type], ["Time", fmtT(classData.time)], ["Teacher", classData.coach], ["Spots", isFull ? `Full -- ${classData.waitlist || 0} waitlisted` : `${classData.capacity - classData.registered} open`]].map(([l, v], i) => (<div key={i} style={{ display: "flex", justifyContent: "space-between", padding: "10px 0", borderBottom: i < 3 ? `1px solid ${T.borderLight}` : "none" }}><span style={{ fontSize: 13, color: T.textMuted }}>{l}</span><span style={{ fontSize: 13, fontWeight: 600, color: l === "Spots" ? (isFull ? T.warning : T.accent) : T.text }}>{v}</span></div>))}</div><div style={{ display: "flex", gap: 10 }}><button onClick={onClose} style={{ flex: 1, padding: "12px 0", borderRadius: 8, border: `1px solid ${T.border}`, background: "transparent", fontSize: 14, fontWeight: 600, cursor: "pointer", color: T.textMuted }}>Cancel</button><button onClick={doConfirm} style={{ flex: 1, padding: "12px 0", borderRadius: 8, border: "none", fontSize: 14, fontWeight: 700, cursor: "pointer", fontFamily: DF, background: T.accent, color: "#fff" }}>{isFull ? "Join Waitlist" : "Confirm"}</button></div></>)}</div></div>); }

// === CONSUMER PAGES ===
function HomePage() {
  const { openReservation, feedCelebrations, celebrateFeed } = useContext(AppContext);
  const now = new Date(); const cm = now.getHours() * 60 + now.getMinutes();
  const upcoming = CLASSES_TODAY.filter(c => { const [h, m] = c.time.split(":").map(Number); return h * 60 + m > cm; });
  return (<div>
    <PageHero title={<>{SC.heroLine1} <span style={{ color: T.accent }}>{SC.heroLine2}</span></>} subtitle={SC.description} img={IMG.home} minH={264} />
    <section style={{ padding: "20px 16px 0" }}><SH title="Today's Practice" linkText="All Classes" linkPage="classes" /><PCard practice={TODAYS_FOCUS} expanded={true} onToggle={() => {}} /></section>
    <section style={{ padding: "0 16px", marginTop: 24 }}><SH title="Up Next" linkText="Full Schedule" linkPage="schedule" />{upcoming.length > 0 ? <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>{upcoming.slice(0, 4).map(c => (<div key={c.id} style={{ display: "flex", alignItems: "center", gap: 12, padding: "12px 14px", background: T.bgCard, border: `1px solid ${T.border}`, borderRadius: 12 }}><div style={{ textAlign: "center", minWidth: 54 }}><span style={{ fontFamily: DF, fontSize: 16, color: T.text, fontWeight: 600 }}>{fmtT(c.time)}</span></div><div style={{ flex: 1 }}><div style={{ display: "flex", alignItems: "center", gap: 6 }}><p style={{ fontWeight: 600, fontSize: 13, color: T.text, margin: 0 }}>{c.type}</p><LocBadge loc={c.location} /></div><p style={{ fontSize: 11, color: T.textMuted, margin: "2px 0 0" }}>{c.coach} -- {c.registered}/{c.capacity}</p></div><button onClick={() => openReservation(c)} style={{ padding: "6px 14px", borderRadius: 8, border: "none", fontSize: 12, fontWeight: 700, cursor: "pointer", background: c.registered >= c.capacity ? T.warningGhost : T.accent, color: c.registered >= c.capacity ? T.warning : "#fff" }}>{c.registered >= c.capacity ? "Waitlist" : "Reserve"}</button></div>))}</div> : <div style={{ display: "flex", flexDirection: "column", alignItems: "center", padding: "30px 20px", color: T.textFaint }}><Moon size={28} style={{ marginBottom: 8 }} /><p style={{ fontSize: 14, fontWeight: 600, margin: 0 }}>No more classes today</p></div>}</section>
    <section style={{ padding: "0 16px", marginTop: 28 }}><SH title="Community" linkText="View All" linkPage="community" /><div style={{ display: "flex", flexDirection: "column", gap: 8 }}>{COMMUNITY_FEED.slice(0, 3).map(item => { const myC = feedCelebrations[item.id] || 0; return (<div key={item.id} style={{ display: "flex", alignItems: "center", gap: 12, padding: "12px 14px", background: `linear-gradient(135deg, ${T.successGhost}, transparent)`, border: `1px solid ${T.successBorder}`, borderRadius: 12 }}><div style={{ width: 40, height: 40, borderRadius: "50%", background: T.accent, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}><Sparkles size={18} color="#fff" /></div><div style={{ flex: 1 }}><p style={{ fontWeight: 600, fontSize: 14, color: T.text, margin: 0 }}>{item.user} <span style={{ color: T.accent }}>{item.milestone}</span></p><p style={{ fontSize: 12, color: "#6b6050", margin: "2px 0 0", lineHeight: 1.4 }}>{item.message.length > 55 ? item.message.slice(0, 55) + "..." : item.message}</p></div><button onClick={() => celebrateFeed(item.id)} style={{ padding: 8, borderRadius: 8, border: "none", background: myC > 0 ? T.accentGhost : "transparent", cursor: "pointer", display: "flex", alignItems: "center", gap: 4 }}><Heart size={18} color={T.accent} fill={myC > 0 ? T.accent : "none"} /><span style={{ fontSize: 12, fontWeight: 600, color: T.accent }}>{item.celebrations + myC}</span></button></div>); })}</div></section>
    <section style={{ padding: "0 16px", marginTop: 28 }}><SH title="Announcements" /><div style={{ display: "flex", flexDirection: "column", gap: 8 }}>{ANNOUNCEMENTS.map(a => (<div key={a.id} style={{ padding: "14px 16px", borderRadius: 12, borderLeft: `4px solid ${a.type === "celebration" ? T.accent : T.textMuted}`, background: a.type === "celebration" ? T.accentGhost : T.bgDim }}><div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", gap: 8 }}><div><h3 style={{ fontSize: 15, fontWeight: 700, color: T.text, margin: 0 }}>{a.title}</h3><p style={{ fontSize: 13, color: "#6b6050", margin: "4px 0 0" }}>{a.message}</p></div>{a.pinned && <span style={{ fontSize: 11, fontWeight: 600, color: T.accent, background: T.accentGhost, padding: "2px 8px", borderRadius: 99 }}>Pinned</span>}</div></div>))}</div></section>
    <section style={{ padding: "0 16px", marginTop: 28 }}><CTACard /></section>
  </div>);
}

function ClassesPage() { const [exp, setExp] = useState(null); const all = [TODAYS_FOCUS, ...PAST_PRACTICES, UPCOMING_PRACTICE].sort((a, b) => b.date.localeCompare(a.date)); return (<div><PageHero title="Classes" subtitle="Past, present, and upcoming practice" img={IMG.classes} /><div style={{ padding: "20px 16px 0", display: "flex", flexDirection: "column", gap: 12 }}>{all.map(p => <PCard key={p.id} practice={p} expanded={exp === p.id} onToggle={() => setExp(exp === p.id ? null : p.id)} />)}</div></div>); }

function SchedulePage() {
  const [selDay, setSelDay] = useState(new Date().getDay() === 0 ? 6 : new Date().getDay() - 1);
  const [locFilter, setLocFilter] = useState("all");
  const { openReservation } = useContext(AppContext);
  const days = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"];
  const dayNames = ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"];
  const filtered = (WEEKLY_SCHEDULE[selDay]?.classes || []).filter(c => locFilter === "all" || c.loc.toLowerCase() === locFilter);
  return (<div><PageHero title="Schedule" subtitle="Reserve across all three studios" img={IMG.schedule} />
    <div style={{ padding: "20px 16px 0" }}>
      <div style={{ display: "flex", gap: 4, marginBottom: 12, overflowX: "auto", paddingBottom: 4 }}>{days.map((d, i) => <button key={d} onClick={() => setSelDay(i)} style={{ padding: "8px 14px", borderRadius: 8, border: "none", fontSize: 13, fontWeight: 600, cursor: "pointer", whiteSpace: "nowrap", background: selDay === i ? T.accent : T.bgDim, color: selDay === i ? "#fff" : T.textMuted }}>{d}</button>)}</div>
      <div style={{ display: "flex", gap: 4, marginBottom: 16 }}>{["all", "nw", "div", "sel"].map(f => <button key={f} onClick={() => setLocFilter(f)} style={{ padding: "6px 10px", borderRadius: 6, border: "none", fontSize: 11, fontWeight: 700, cursor: "pointer", textTransform: "uppercase", background: locFilter === f ? T.accent : T.bgCard, color: locFilter === f ? "#fff" : T.textMuted }}>{f === "all" ? "All" : f === "nw" ? "N Wms" : f === "div" ? "Division" : "Sellwood"}</button>)}</div>
      <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>{filtered.map((cls, i) => { const isSpecial = cls.type.includes("Yin") || cls.type.includes("Restorative"); return (<div key={i} style={{ display: "flex", alignItems: "center", gap: 14, padding: "14px 16px", background: T.bgCard, border: `1px solid ${T.border}`, borderRadius: 12 }}><div style={{ textAlign: "center", minWidth: 56 }}><span style={{ fontFamily: DF, fontSize: 18, color: T.text, fontWeight: 600 }}>{fmtT(cls.time)}</span></div><div style={{ flex: 1 }}><div style={{ display: "flex", alignItems: "center", gap: 6 }}><p style={{ fontWeight: 600, fontSize: 14, color: T.text, margin: 0 }}>{cls.type}</p><LocBadge loc={cls.loc} />{isSpecial && <span style={{ fontSize: 10, fontWeight: 700, textTransform: "uppercase", padding: "1px 6px", borderRadius: 4, background: T.warningGhost, color: T.warning }}>Restorative</span>}</div>{cls.coach && <p style={{ fontSize: 12, color: T.textMuted, margin: "3px 0 0" }}>{cls.coach}</p>}</div><button onClick={() => openReservation({ id: `s-${selDay}-${i}`, time: cls.time, type: cls.type, coach: cls.coach || "TBD", capacity: isSpecial ? SC.specialtyCapacity : SC.classCapacity, registered: Math.floor(Math.random() * 8) + 14, waitlist: 0, dayLabel: dayNames[selDay] })} style={{ padding: "8px 16px", borderRadius: 8, border: "none", fontSize: 13, fontWeight: 600, cursor: "pointer", background: T.accent, color: "#fff" }}>Reserve</button></div>); })}</div>
    </div>
  </div>);
}

function PracticePage() { const [tab, setTab] = useState("log"); const [ref, setRef] = useState({ energy: 4, focus: 4, notes: "" }); const [saved, setSaved] = useState(null); return (<div><PageHero title="My Practice" subtitle="Track your journey and celebrate growth" img={IMG.practice} /><div style={{ padding: "20px 16px 0" }}><div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 8, marginBottom: 20 }}>{[{ icon: Flame, val: 18, label: "Day Streak", c: T.accent, bg: T.accentGhost, bd: T.accentBorder }, { icon: Star, val: 156, label: "Total Classes", c: T.success, bg: T.successGhost, bd: T.successBorder }, { icon: Mountain, val: 9, label: "Milestones", c: T.warning, bg: T.warningGhost, bd: T.warningBorder }].map((s, i) => (<div key={i} style={{ background: s.bg, border: `1px solid ${s.bd}`, borderRadius: 12, padding: "14px 12px", textAlign: "center" }}><s.icon size={20} color={s.c} style={{ margin: "0 auto 4px" }} /><div style={{ fontFamily: DF, fontSize: 28, fontWeight: 700, color: T.text }}>{s.val}</div><div style={{ fontSize: 11, color: T.textMuted, fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.05em" }}>{s.label}</div></div>))}</div><div style={{ display: "flex", gap: 4, marginBottom: 20, background: T.bgDim, borderRadius: 10, padding: 4 }}>{[{ id: "log", label: "Reflection" }, { id: "milestones", label: "Milestones" }].map(t => <button key={t.id} onClick={() => setTab(t.id)} style={{ flex: 1, padding: "10px 0", borderRadius: 8, border: "none", fontSize: 13, fontWeight: 600, cursor: "pointer", background: tab === t.id ? T.bgCard : "transparent", color: tab === t.id ? T.text : T.textMuted, boxShadow: tab === t.id ? "0 1px 3px rgba(0,0,0,.06)" : "none" }}>{t.label}</button>)}</div>{tab === "log" && (<div style={{ background: T.bgCard, border: `1px solid ${T.border}`, borderRadius: 12, padding: 20 }}><div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 16 }}><Sparkles size={18} color={T.accent} /><h3 style={{ margin: 0, fontSize: 16, fontWeight: 700 }}>Post-Practice Reflection</h3></div><div style={{ display: "flex", flexDirection: "column", gap: 16 }}>{[{ label: "Energy Level", key: "energy", icons: [Moon, Moon, Sun, Sun, Sparkles], c: T.accent }, { label: "Focus & Presence", key: "focus", icons: [Wind, Wind, Heart, Heart, Sparkles], c: T.success }].map(row => (<div key={row.key}><label style={{ display: "block", fontSize: 12, fontWeight: 600, color: T.textMuted, marginBottom: 8, textTransform: "uppercase", letterSpacing: "0.05em" }}>{row.label}</label><div style={{ display: "flex", gap: 6 }}>{[1,2,3,4,5].map(n => { const I = row.icons[n-1]; return <button key={n} onClick={() => setRef({...ref, [row.key]: n})} style={{ width: 44, height: 44, borderRadius: 10, border: `1px solid ${ref[row.key] >= n ? row.c : T.border}`, background: ref[row.key] >= n ? `${row.c}12` : "transparent", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center" }}><I size={18} color={ref[row.key] >= n ? row.c : T.textFaint} /></button>; })}</div></div>))}<IF label="Notes / Gratitude" value={ref.notes} onChange={v => setRef({...ref, notes: v})} placeholder="What came up for you on the mat today?" multiline /><button onClick={() => { setSaved("log"); setTimeout(() => setSaved(null), 2000); setRef({ energy: 4, focus: 4, notes: "" }); }} style={{ padding: "12px 0", borderRadius: 8, border: "none", fontWeight: 700, cursor: "pointer", background: T.accent, color: "#fff", fontFamily: DF, fontSize: 17 }}>{saved === "log" ? <><Check size={16} style={{ display: "inline", verticalAlign: "middle" }} /> Saved</> : "Save Reflection"}</button></div></div>)}{tab === "milestones" && (<div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>{Object.entries(MILESTONE_BADGES).map(([name, badge]) => { const earned = ["First Class", "10 Classes", "50 Classes", "100 Classes", "7-Day Streak", "30-Day Streak", "All 3 Studios", "1 Year Member"].includes(name); const Icon = badge.icon; return (<div key={name} style={{ background: earned ? T.bgCard : T.bgDim, border: `1px solid ${earned ? T.border : "transparent"}`, borderRadius: 12, padding: "16px 14px", textAlign: "center", opacity: earned ? 1 : 0.45 }}><div style={{ width: 44, height: 44, borderRadius: "50%", background: earned ? `${badge.color}18` : T.bgDim, display: "flex", alignItems: "center", justifyContent: "center", margin: "0 auto 8px" }}><Icon size={22} color={earned ? badge.color : T.textFaint} /></div><p style={{ fontSize: 13, fontWeight: 700, color: earned ? T.text : T.textFaint, margin: 0 }}>{name}</p><p style={{ fontSize: 11, color: T.textFaint, margin: "2px 0 0" }}>{earned ? "Earned" : "Keep going"}</p></div>); })}</div>)}</div></div>); }

function CommunityPage() { const { feedCelebrations, celebrateFeed } = useContext(AppContext); return (<div><PageHero title="Community" subtitle="Celebrate each other's practice" img={IMG.community} /><div style={{ padding: "20px 16px 0", display: "flex", flexDirection: "column", gap: 10 }}>{COMMUNITY_FEED.map(item => { const myC = feedCelebrations[item.id] || 0; return (<div key={item.id} style={{ background: T.bgCard, border: `1px solid ${T.border}`, borderRadius: 14, padding: "16px 18px" }}><div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 10 }}><div style={{ width: 40, height: 40, borderRadius: "50%", background: `linear-gradient(135deg, ${T.accent}, ${T.accentDark})`, display: "flex", alignItems: "center", justifyContent: "center", fontFamily: DF, fontSize: 16, color: "#fff", fontWeight: 700, flexShrink: 0 }}>{item.user[0]}</div><div><p style={{ fontWeight: 700, fontSize: 14, margin: 0, color: T.text }}>{item.user}</p><p style={{ fontSize: 12, color: T.textMuted, margin: "1px 0 0" }}>{fmtDS(item.date)}</p></div><span style={{ marginLeft: "auto", fontSize: 11, fontWeight: 700, padding: "3px 10px", borderRadius: 6, background: T.accentGhost, color: T.accent }}>{item.milestone}</span></div><p style={{ fontSize: 14, color: "#4a4230", lineHeight: 1.5, margin: "0 0 12px" }}>{item.message}</p><button onClick={() => celebrateFeed(item.id)} style={{ display: "flex", alignItems: "center", gap: 6, padding: "6px 12px", borderRadius: 8, border: `1px solid ${myC > 0 ? T.accentBorder : T.border}`, background: myC > 0 ? T.accentGhost : "transparent", cursor: "pointer" }}><Heart size={16} color={T.accent} fill={myC > 0 ? T.accent : "none"} /><span style={{ fontSize: 13, fontWeight: 600, color: T.accent }}>{item.celebrations + myC}</span></button></div>); })}</div></div>); }

function TeachersPage() { const [exp, setExp] = useState(null); return (<div><PageHero title="Our Teachers" subtitle="Some of the best yoga instructors in Portland" img={IMG.teachers} /><div style={{ padding: "20px 16px 0", display: "flex", flexDirection: "column", gap: 12 }}>{TEACHERS.map(t => { const expanded = exp === t.id; return (<div key={t.id} onClick={() => setExp(expanded ? null : t.id)} style={{ background: T.bgCard, border: `1px solid ${T.border}`, borderRadius: 14, overflow: "hidden", cursor: "pointer" }}><div style={{ display: "flex", alignItems: "center", gap: 14, padding: "16px 18px" }}><div style={{ width: 56, height: 56, borderRadius: 14, background: `linear-gradient(135deg, ${T.accent}, ${T.accentDark})`, display: "flex", alignItems: "center", justifyContent: "center", fontFamily: DF, fontSize: 22, color: "#fff", flexShrink: 0, fontWeight: 700 }}>{t.firstName[0]}{t.lastName[0]}</div><div style={{ flex: 1 }}><h3 style={{ fontSize: 16, fontWeight: 700, margin: 0, color: T.text }}>{t.firstName} {t.lastName}</h3><p style={{ fontSize: 13, color: T.accent, fontWeight: 600, margin: "2px 0 0" }}>{t.role}</p><p style={{ fontSize: 12, color: T.textMuted, margin: "2px 0 0" }}>{t.yearsTeaching} years teaching</p></div><ChevronDown size={18} color={T.textFaint} style={{ transform: expanded ? "rotate(180deg)" : "none", transition: "transform 0.2s" }} /></div>{expanded && <div style={{ padding: "0 18px 18px", borderTop: `1px solid ${T.borderLight}`, paddingTop: 14 }}><p style={{ fontSize: 13, color: "#5a5040", lineHeight: 1.6, margin: "0 0 12px" }}>{t.bio}</p><div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginBottom: 10 }}>{t.specialties.map(s => <span key={s} style={{ fontSize: 11, fontWeight: 600, padding: "3px 8px", borderRadius: 6, background: T.accentGhost, color: T.accent }}>{s}</span>)}</div><div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>{t.certs.map(c => <span key={c} style={{ fontSize: 11, fontWeight: 600, padding: "3px 8px", borderRadius: 6, background: T.bgDim, color: T.textMuted }}>{c}</span>)}</div></div>}</div>); })}</div></div>); }

function MembershipPage() { return (<div><PageHero title="Pricing" subtitle="Find your path to practice" img={IMG.membership} /><div style={{ padding: "20px 16px 0", display: "flex", flexDirection: "column", gap: 12 }}>{MEMBERSHIP_TIERS.map(tier => (<div key={tier.id} style={{ background: T.bgCard, border: `1px solid ${tier.popular ? T.accent : T.border}`, borderRadius: 14, padding: "20px 18px", position: "relative", overflow: "hidden" }}>{tier.popular && <div style={{ position: "absolute", top: 12, right: -28, background: T.accent, color: "#fff", fontSize: 10, fontWeight: 700, padding: "3px 32px", transform: "rotate(45deg)", textTransform: "uppercase", letterSpacing: "0.05em" }}>Best Value</div>}<h3 style={{ fontFamily: DF, fontSize: 22, margin: "0 0 4px", color: T.text, fontWeight: 700 }}>{tier.name}</h3><div style={{ display: "flex", alignItems: "baseline", gap: 4, marginBottom: 12 }}><span style={{ fontFamily: DF, fontSize: 38, color: T.accent, fontWeight: 700 }}>${tier.price}</span><span style={{ fontSize: 13, color: T.textMuted }}>{tier.period}</span></div><ul style={{ listStyle: "none", padding: 0, margin: "0 0 16px" }}>{tier.features.map((f, i) => <li key={i} style={{ display: "flex", alignItems: "center", gap: 8, padding: "4px 0", fontSize: 13, color: "#5a5040" }}><CircleCheck size={14} color={T.accent} style={{ flexShrink: 0 }} />{f}</li>)}</ul><button style={{ width: "100%", padding: "12px 0", borderRadius: 8, border: "none", fontSize: 16, fontWeight: 700, cursor: "pointer", fontFamily: DF, background: tier.popular ? T.accent : T.bg, color: "#fff" }}>Get Started</button></div>))}</div></div>); }

function EventsPage() { return (<div><PageHero title="Events" subtitle="Workshops, rituals, and experiences" img={IMG.events} /><div style={{ padding: "20px 16px 0" }}>{EVENTS.map(ev => (<div key={ev.id} style={{ background: T.bgCard, border: `1px solid ${T.border}`, borderRadius: 14, overflow: "hidden", marginBottom: 16 }}><div style={{ background: `linear-gradient(135deg, ${T.bg}, hsl(38,30%,18%))`, padding: "20px 18px", color: "#fff" }}><div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 4 }}><span style={{ fontSize: 11, fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.1em", color: T.accent }}>{ev.type}</span>{ev.location !== "offsite" && <LocBadge loc={ev.location} />}</div><h3 style={{ fontFamily: DF, fontSize: 22, margin: "6px 0 4px", fontWeight: 700 }}>{ev.name}</h3><div style={{ display: "flex", alignItems: "center", gap: 12, fontSize: 13, color: "#b8a898" }}><span style={{ display: "flex", alignItems: "center", gap: 4 }}><Calendar size={14} /> {fmtDS(ev.date)}</span><span style={{ display: "flex", alignItems: "center", gap: 4 }}><Clock size={14} /> {fmtT(ev.startTime)}</span></div></div><div style={{ padding: "16px 18px" }}><p style={{ fontSize: 13, color: "#5a5040", lineHeight: 1.6, margin: "0 0 14px" }}>{ev.description}</p><div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, marginBottom: 16 }}><SB label="Price" value={ev.fee === 0 ? "Class rate" : `$${ev.fee}`} /><SB label="Spots" value={`${ev.registered}/${ev.maxParticipants}`} /></div><button style={{ width: "100%", padding: "12px 0", borderRadius: 8, border: "none", fontSize: 16, fontWeight: 700, cursor: "pointer", fontFamily: DF, background: T.accent, color: "#fff" }}>Register Now</button></div></div>))}</div></div>); }

// === ADMIN PAGES ===
function AdminDashboard() { const metrics = [{ label: "Active Members", value: ADMIN_METRICS.activeMembers, change: `+${ADMIN_METRICS.memberChange}`, icon: Users, color: T.accent }, { label: "Today's Check-ins", value: ADMIN_METRICS.todayCheckIns, change: `${ADMIN_METRICS.weekCheckIns}/wk`, icon: Calendar, color: T.success }, { label: "Monthly Revenue", value: `$${ADMIN_METRICS.monthlyRevenue.toLocaleString()}`, change: `+${ADMIN_METRICS.revenueChange}%`, icon: DollarSign, color: T.warning }, { label: "Scholarships Active", value: ADMIN_METRICS.scholarships, change: "Funded by community", icon: Heart, color: "#8b5cf6" }]; return (<div style={{ display: "flex", flexDirection: "column", gap: 20 }}><div><h1 style={{ fontFamily: DF, fontSize: 28, color: "#111827", margin: 0, fontWeight: 700 }}>Dashboard</h1><p style={{ fontSize: 13, color: "#6b7280", margin: "4px 0 0" }}>N Williams + SE Division + Sellwood</p></div><div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))", gap: 14 }}>{metrics.map((m, i) => (<div key={i} style={{ background: "#fff", border: "1px solid #e5e7eb", borderRadius: 12, padding: 18 }}><div style={{ width: 36, height: 36, borderRadius: 8, background: `${m.color}18`, display: "flex", alignItems: "center", justifyContent: "center", marginBottom: 12 }}><m.icon size={18} color={m.color} /></div><div style={{ fontFamily: DF, fontSize: 30, color: "#111827", fontWeight: 700 }}>{m.value}</div><span style={{ display: "flex", alignItems: "center", fontSize: 12, fontWeight: 600, color: "#4ade80", marginTop: 4 }}><ArrowUpRight size={12} /> {m.change}</span><p style={{ fontSize: 13, color: "#6b7280", margin: "6px 0 0" }}>{m.label}</p></div>))}</div><div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(320px, 1fr))", gap: 14 }}><AC title="Attendance by Location"><div style={{ height: 220 }}><ResponsiveContainer width="100%" height="100%"><BarChart data={ADMIN_CHARTS.attendance}><CartesianGrid strokeDasharray="3 3" stroke="#e5e7eb" /><XAxis dataKey="day" stroke="#6b7280" fontSize={12} /><YAxis stroke="#6b7280" fontSize={12} /><Tooltip contentStyle={{ backgroundColor: "#fff", border: "1px solid #e5e7eb", borderRadius: 8, color: "#111827" }} /><Bar dataKey="NW" fill={T.accent} radius={[4, 4, 0, 0]} /><Bar dataKey="DIV" fill={T.success} radius={[4, 4, 0, 0]} /><Bar dataKey="SEL" fill="#8b5cf6" radius={[4, 4, 0, 0]} /></BarChart></ResponsiveContainer></div><div style={{ display: "flex", gap: 12, justifyContent: "center", marginTop: 8 }}>{[{ l: "N Williams", c: T.accent }, { l: "SE Division", c: T.success }, { l: "Sellwood", c: "#8b5cf6" }].map((x, i) => <div key={i} style={{ display: "flex", alignItems: "center", gap: 4 }}><div style={{ width: 8, height: 8, borderRadius: "50%", background: x.c }} /><span style={{ fontSize: 11, color: "#6b7280" }}>{x.l}</span></div>)}</div></AC><AC title="Revenue Trend"><div style={{ height: 220 }}><ResponsiveContainer width="100%" height="100%"><AreaChart data={ADMIN_CHARTS.revenue}><CartesianGrid strokeDasharray="3 3" stroke="#e5e7eb" /><XAxis dataKey="month" stroke="#6b7280" fontSize={12} /><YAxis stroke="#6b7280" fontSize={12} tickFormatter={v => `$${v / 1000}k`} /><Tooltip contentStyle={{ backgroundColor: "#fff", border: "1px solid #e5e7eb", borderRadius: 8, color: "#111827" }} formatter={v => [`$${v.toLocaleString()}`, "Revenue"]} /><defs><linearGradient id="rg" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stopColor={T.accent} stopOpacity={0.3} /><stop offset="100%" stopColor={T.accent} stopOpacity={0} /></linearGradient></defs><Area type="monotone" dataKey="revenue" stroke={T.accent} fill="url(#rg)" /></AreaChart></ResponsiveContainer></div></AC></div><div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(280px, 1fr))", gap: 14 }}><AC title="Membership Breakdown"><div style={{ height: 200 }}><ResponsiveContainer width="100%" height="100%"><PieChart><Pie data={ADMIN_CHARTS.membershipBreakdown} cx="50%" cy="50%" innerRadius={50} outerRadius={80} dataKey="value" paddingAngle={4}>{ADMIN_CHARTS.membershipBreakdown.map((e, i) => <Cell key={i} fill={e.color} />)}</Pie><Tooltip contentStyle={{ backgroundColor: "#fff", border: "1px solid #e5e7eb", borderRadius: 8, color: "#111827" }} /></PieChart></ResponsiveContainer></div><div style={{ display: "flex", flexWrap: "wrap", gap: 10, justifyContent: "center" }}>{ADMIN_CHARTS.membershipBreakdown.map((e, i) => <div key={i} style={{ display: "flex", alignItems: "center", gap: 4 }}><div style={{ width: 8, height: 8, borderRadius: "50%", background: e.color }} /><span style={{ fontSize: 11, color: "#6b7280" }}>{e.name} ({e.value})</span></div>)}</div></AC><AC title="Class Fill Rate"><div style={{ display: "flex", flexDirection: "column", gap: 10 }}>{ADMIN_CHARTS.classPopularity.map((c, i) => <div key={i}><div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}><span style={{ fontSize: 12, color: "#374151", fontWeight: 600 }}>{c.name}</span><span style={{ fontSize: 11, color: "#6b7280" }}>{c.pct}%</span></div><div style={{ height: 6, background: "#e5e7eb", borderRadius: 3, overflow: "hidden" }}><div style={{ height: "100%", width: `${c.pct}%`, background: T.accent, borderRadius: 3 }} /></div></div>)}</div></AC></div></div>); }

function AdminMembersPage() { const [search, setSearch] = useState(""); const [filter, setFilter] = useState("all"); const filtered = MEMBERS_DATA.filter(m => m.name.toLowerCase().includes(search.toLowerCase()) && (filter === "all" || m.status === filter)); return (<div style={{ display: "flex", flexDirection: "column", gap: 16 }}><div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}><h1 style={{ fontFamily: DF, fontSize: 28, color: "#111827", margin: 0, fontWeight: 700 }}>Members</h1><button style={{ display: "flex", alignItems: "center", gap: 6, padding: "8px 16px", borderRadius: 8, border: "none", background: T.accent, color: "#fff", fontWeight: 600, fontSize: 13, cursor: "pointer" }}><UserPlus size={16} /> Add Member</button></div><div style={{ display: "flex", gap: 10 }}><div style={{ flex: 1, position: "relative" }}><Search size={16} style={{ position: "absolute", left: 12, top: "50%", transform: "translateY(-50%)", color: "#6b7280" }} /><input value={search} onChange={e => setSearch(e.target.value)} placeholder="Search members..." style={{ width: "100%", padding: "10px 12px 10px 36px", background: "#fff", border: "1px solid #e5e7eb", borderRadius: 8, color: "#111827", fontSize: 13, outline: "none", boxSizing: "border-box" }} /></div><div style={{ display: "flex", gap: 4 }}>{["all", "active", "frozen"].map(f => <button key={f} onClick={() => setFilter(f)} style={{ padding: "8px 14px", borderRadius: 8, border: "none", fontSize: 12, fontWeight: 600, cursor: "pointer", textTransform: "capitalize", background: filter === f ? T.accent : "#fff", color: filter === f ? "#fff" : "#6b7280" }}>{f}</button>)}</div></div><div style={{ background: "#fff", border: "1px solid #e5e7eb", borderRadius: 12, overflow: "hidden" }}><table style={{ width: "100%", borderCollapse: "collapse", fontSize: 13 }}><thead><tr style={{ borderBottom: "1px solid #e5e7eb" }}>{["Member", "Plan", "Status", "Classes", "Studio"].map(h => <th key={h} style={{ padding: "12px 16px", textAlign: "left", color: "#6b7280", fontWeight: 600, fontSize: 11, textTransform: "uppercase" }}>{h}</th>)}</tr></thead><tbody>{filtered.map(m => <tr key={m.id} style={{ borderBottom: "1px solid #e5e7eb" }}><td style={{ padding: "12px 16px" }}><p style={{ color: "#111827", fontWeight: 600, margin: 0 }}>{m.name}</p><p style={{ color: "#6b7280", fontSize: 12, margin: "2px 0 0" }}>{m.email}</p></td><td style={{ padding: "12px 16px", color: "#374151" }}>{m.membership}</td><td style={{ padding: "12px 16px" }}><span style={{ padding: "3px 8px", borderRadius: 6, fontSize: 11, fontWeight: 600, textTransform: "capitalize", background: m.status === "active" ? `${T.accent}20` : `${T.warning}20`, color: m.status === "active" ? T.accent : T.warning }}>{m.status}</span></td><td style={{ padding: "12px 16px", color: "#374151", fontFamily: "monospace" }}>{m.checkIns}</td><td style={{ padding: "12px 16px", color: "#6b7280" }}>{m.location}</td></tr>)}</tbody></table></div></div>); }

function AdminSchedulePage() { return (<div style={{ display: "flex", flexDirection: "column", gap: 16 }}><div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}><h1 style={{ fontFamily: DF, fontSize: 28, color: "#111827", margin: 0, fontWeight: 700 }}>Schedule</h1><button style={{ display: "flex", alignItems: "center", gap: 6, padding: "8px 16px", borderRadius: 8, border: "none", background: T.accent, color: "#fff", fontWeight: 600, fontSize: 13, cursor: "pointer" }}><Plus size={16} /> Add Class</button></div><div style={{ background: "#fff", border: "1px solid #e5e7eb", borderRadius: 12, overflow: "hidden" }}><table style={{ width: "100%", borderCollapse: "collapse", fontSize: 13 }}><thead><tr style={{ borderBottom: "1px solid #e5e7eb" }}>{["Time", "Class", "Teacher", "Studio", "Spots", ""].map(h => <th key={h} style={{ padding: "12px 16px", textAlign: "left", color: "#6b7280", fontWeight: 600, fontSize: 11, textTransform: "uppercase" }}>{h}</th>)}</tr></thead><tbody>{CLASSES_TODAY.map(c => <tr key={c.id} style={{ borderBottom: "1px solid #e5e7eb" }}><td style={{ padding: "12px 16px", color: "#111827", fontFamily: "monospace" }}>{fmtT(c.time)}</td><td style={{ padding: "12px 16px", color: "#374151", fontWeight: 600 }}>{c.type}</td><td style={{ padding: "12px 16px", color: "#374151" }}>{c.coach}</td><td style={{ padding: "12px 16px", color: "#6b7280" }}>{c.location.toUpperCase()}</td><td style={{ padding: "12px 16px" }}><span style={{ fontFamily: "monospace", fontWeight: 600, color: c.registered >= c.capacity ? T.warning : T.accent }}>{c.registered}/{c.capacity}</span></td><td style={{ padding: "12px 16px" }}><div style={{ display: "flex", gap: 4 }}><button style={{ padding: "4px 8px", borderRadius: 4, border: "1px solid #e5e7eb", background: "transparent", color: "#6b7280", cursor: "pointer" }}><Edit3 size={12} /></button><button style={{ padding: "4px 8px", borderRadius: 4, border: "1px solid #e5e7eb", background: "transparent", color: "#6b7280", cursor: "pointer" }}><Trash2 size={12} /></button></div></td></tr>)}</tbody></table></div></div>); }

function AdminTeachersPage() { return (<div style={{ display: "flex", flexDirection: "column", gap: 16 }}><div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}><h1 style={{ fontFamily: DF, fontSize: 28, color: "#111827", margin: 0, fontWeight: 700 }}>Teachers</h1><button style={{ display: "flex", alignItems: "center", gap: 6, padding: "8px 16px", borderRadius: 8, border: "none", background: T.accent, color: "#fff", fontWeight: 600, fontSize: 13, cursor: "pointer" }}><UserPlus size={16} /> Add Teacher</button></div><div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(300px, 1fr))", gap: 14 }}>{TEACHERS.map(t => (<div key={t.id} style={{ background: "#fff", border: "1px solid #e5e7eb", borderRadius: 12, padding: 18 }}><div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 12 }}><div style={{ width: 48, height: 48, borderRadius: 10, background: `linear-gradient(135deg, ${T.accent}, ${T.accentDark})`, display: "flex", alignItems: "center", justifyContent: "center", fontFamily: DF, fontSize: 20, color: "#fff", fontWeight: 700 }}>{t.firstName[0]}{t.lastName[0]}</div><div><h3 style={{ fontSize: 15, fontWeight: 700, color: "#111827", margin: 0 }}>{t.firstName} {t.lastName}</h3><p style={{ fontSize: 12, color: T.accent, fontWeight: 600, margin: "2px 0 0" }}>{t.role}</p></div></div><div style={{ display: "flex", flexWrap: "wrap", gap: 4, marginBottom: 10 }}>{t.certs.map(c => <span key={c} style={{ fontSize: 10, fontWeight: 600, padding: "2px 6px", borderRadius: 4, background: "#e5e7eb", color: "#6b7280" }}>{c}</span>)}</div><div style={{ display: "flex", gap: 6 }}><button style={{ flex: 1, padding: "8px 0", borderRadius: 6, border: "1px solid #e5e7eb", background: "transparent", color: "#374151", fontSize: 12, fontWeight: 600, cursor: "pointer" }}>Edit</button><button style={{ flex: 1, padding: "8px 0", borderRadius: 6, border: "1px solid #e5e7eb", background: "transparent", color: "#374151", fontSize: 12, fontWeight: 600, cursor: "pointer" }}>Schedule</button><button style={{ padding: "8px", borderRadius: 6, border: "1px solid #e5e7eb", background: "transparent", color: "#6b7280", cursor: "pointer" }}><Trash2 size={14} /></button></div></div>))}</div></div>); }

function AdminEventsPage() { return (<div style={{ display: "flex", flexDirection: "column", gap: 16 }}><div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}><h1 style={{ fontFamily: DF, fontSize: 28, color: "#111827", margin: 0, fontWeight: 700 }}>Events</h1><button style={{ display: "flex", alignItems: "center", gap: 6, padding: "8px 16px", borderRadius: 8, border: "none", background: T.accent, color: "#fff", fontWeight: 600, fontSize: 13, cursor: "pointer" }}><Plus size={16} /> Add Event</button></div>{EVENTS.map(ev => (<div key={ev.id} style={{ background: "#fff", border: "1px solid #e5e7eb", borderRadius: 12, padding: 18 }}><div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}><div><h3 style={{ color: "#111827", fontWeight: 700, fontSize: 15, margin: "0 0 4px" }}>{ev.name}</h3><p style={{ color: "#6b7280", fontSize: 12 }}>{fmtDS(ev.date)} -- {ev.type}</p></div><div style={{ display: "flex", gap: 4 }}><button style={{ padding: "6px 10px", borderRadius: 6, border: "1px solid #e5e7eb", background: "transparent", color: "#374151", cursor: "pointer" }}><Edit3 size={14} /></button><button style={{ padding: "6px 10px", borderRadius: 6, border: "1px solid #e5e7eb", background: "transparent", color: "#6b7280", cursor: "pointer" }}><Trash2 size={14} /></button></div></div><div style={{ display: "flex", gap: 16, marginTop: 8 }}><span style={{ fontSize: 12, color: "#6b7280" }}>{ev.fee === 0 ? "Class rate" : `$${ev.fee}`}</span><span style={{ fontSize: 12, color: "#6b7280" }}>{ev.registered}/{ev.maxParticipants}</span><span style={{ fontSize: 12, fontWeight: 600, color: T.accent }}>{ev.status}</span></div></div>))}</div>); }

function AdminPricingPage() { return (<div style={{ display: "flex", flexDirection: "column", gap: 16 }}><div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}><h1 style={{ fontFamily: DF, fontSize: 28, color: "#111827", margin: 0, fontWeight: 700 }}>Pricing</h1><button style={{ display: "flex", alignItems: "center", gap: 6, padding: "8px 16px", borderRadius: 8, border: "none", background: T.accent, color: "#fff", fontWeight: 600, fontSize: 13, cursor: "pointer" }}><Plus size={16} /> Add Tier</button></div>{MEMBERSHIP_TIERS.map(tier => (<div key={tier.id} style={{ background: "#fff", border: `1px solid ${tier.popular ? T.accent : "#e5e7eb"}`, borderRadius: 12, padding: 18 }}><div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}><div><h3 style={{ color: "#111827", fontWeight: 700, fontSize: 15, margin: 0 }}>{tier.name}</h3><p style={{ color: T.accent, fontSize: 22, fontFamily: DF, fontWeight: 700, margin: "4px 0 0" }}>${tier.price} <span style={{ fontSize: 13, color: "#6b7280", fontFamily: "'DM Sans'" }}>{tier.period}</span></p></div><div style={{ display: "flex", gap: 4 }}><button style={{ padding: "6px 10px", borderRadius: 6, border: "1px solid #e5e7eb", background: "transparent", color: "#374151", cursor: "pointer" }}><Edit3 size={14} /></button><button style={{ padding: "6px 10px", borderRadius: 6, border: "1px solid #e5e7eb", background: "transparent", color: "#6b7280", cursor: "pointer" }}><Trash2 size={14} /></button></div></div></div>))}</div>); }

function AdminCommsPage() { const [msg, setMsg] = useState(""); const [sent, setSent] = useState(false); return (<div style={{ display: "flex", flexDirection: "column", gap: 16 }}><h1 style={{ fontFamily: DF, fontSize: 28, color: "#111827", margin: 0, fontWeight: 700 }}>Broadcast</h1><AC title="New Announcement"><textarea value={msg} onChange={e => setMsg(e.target.value)} placeholder="Broadcast to all members..." rows={4} style={{ width: "100%", padding: 12, background: "#f3f4f6", border: "1px solid #e5e7eb", borderRadius: 8, color: "#111827", fontSize: 13, fontFamily: "'DM Sans'", resize: "none", outline: "none", boxSizing: "border-box", marginBottom: 12 }} /><button onClick={() => { setSent(true); setTimeout(() => { setSent(false); setMsg(""); }, 2000); }} disabled={!msg.trim()} style={{ display: "flex", alignItems: "center", gap: 6, padding: "10px 20px", borderRadius: 8, border: "none", background: msg.trim() ? T.accent : "#e5e7eb", color: "#fff", fontWeight: 600, fontSize: 13, cursor: msg.trim() ? "pointer" : "default" }}>{sent ? <><Check size={14} /> Sent!</> : <><Send size={14} /> Broadcast to All</>}</button></AC><AC title="Recent Broadcasts">{ANNOUNCEMENTS.map(a => <div key={a.id} style={{ padding: "12px 0", borderBottom: "1px solid #e5e7eb" }}><p style={{ color: "#111827", fontWeight: 600, fontSize: 14, margin: 0 }}>{a.title}</p><p style={{ color: "#6b7280", fontSize: 12, margin: "4px 0 0" }}>{a.message}</p></div>)}</AC></div>); }

function AdminSettingsPage() { return (<div style={{ display: "flex", flexDirection: "column", gap: 16 }}><h1 style={{ fontFamily: DF, fontSize: 28, color: "#111827", margin: 0, fontWeight: 700 }}>Settings</h1><AC title="Studio Locations"><div style={{ display: "flex", flexDirection: "column", gap: 12 }}>{SC.locations.map(loc => <div key={loc.id} style={{ display: "flex", alignItems: "center", gap: 12, padding: 12, borderRadius: 8, background: "#f3f4f6" }}><MapPin size={18} color={T.accent} /><div><p style={{ color: "#111827", fontWeight: 600, fontSize: 14, margin: 0 }}>{loc.name}</p><p style={{ color: "#6b7280", fontSize: 12, margin: "2px 0 0" }}>{loc.address}</p></div><button style={{ marginLeft: "auto", padding: "4px 10px", borderRadius: 6, border: "1px solid #e5e7eb", background: "transparent", color: "#374151", fontSize: 12, cursor: "pointer" }}><Edit3 size={14} /></button></div>)}</div></AC><AC title="Integrations">{["MindBody (Booking)", "Payment Processor", "Email Marketing", "Analytics"].map((item, i) => <div key={i} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "10px 0", borderBottom: i < 3 ? "1px solid #e5e7eb" : "none" }}><span style={{ color: "#374151", fontSize: 13 }}>{item}</span><span style={{ fontSize: 11, fontWeight: 600, padding: "3px 8px", borderRadius: 4, background: `${T.accent}20`, color: T.accent }}>Connected</span></div>)}</AC></div>); }

// === MAIN APP ===
export default function App({ startInAdmin, onExitAdmin, onEnterAdmin } = {}) {
  const [page, setPage] = useState("home");
  const [isAdmin, setIsAdmin] = useState(startInAdmin || false);
  const [showMore, setShowMore] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);
  const [classReg, setClassReg] = useState({});
  const [resClass, setResClass] = useState(null);
  const [feedCel, setFeedCel] = useState({});
  const contentRef = useRef(null);

  useEffect(() => { window.scrollTo(0, 0); const c = document.getElementById("app-scroll-container"); if (c) c.scrollTo(0, 0); if (contentRef.current) contentRef.current.scrollTo(0, 0); }, [page]);

  const regClass = useCallback((id) => setClassReg(p => ({ ...p, [id]: true })), []);
  const openRes = useCallback((d) => setResClass(d), []);
  const celFeed = useCallback((id) => setFeedCel(p => ({ ...p, [id]: (p[id] || 0) + 1 })), []);

  const mainTabs = [{ id: "home", label: "Home", icon: Home }, { id: "schedule", label: "Schedule", icon: CalendarDays }, { id: "practice", label: "Practice", icon: TrendingUp }, { id: "community", label: "Community", icon: Heart }, { id: "more", label: "More", icon: Menu }];
  const moreItems = [{ id: "classes", label: "Classes", icon: Calendar }, { id: "teachers", label: "Teachers", icon: Users }, { id: "membership", label: "Pricing", icon: CreditCard }, { id: "events", label: "Events", icon: PartyPopper }, { id: "rewards", label: "NOW Points", icon: Gift }];
  const adminTabs = [{ id: "admin-dashboard", label: "Dashboard", icon: LayoutDashboard }, { id: "admin-members", label: "Members", icon: Users }, { id: "admin-schedule", label: "Schedule", icon: CalendarDays }, { id: "admin-teachers", label: "Teachers", icon: UserCheck }, { id: "admin-events", label: "Events", icon: PartyPopper }, { id: "admin-pricing", label: "Pricing", icon: CreditCard }, { id: "admin-comms", label: "Broadcast", icon: Megaphone }, { id: "admin-settings", label: "Settings", icon: Settings }];
  const isMoreActive = moreItems.some(item => item.id === page);

  const renderPage = () => {
    switch (page) {
      case "home": return <HomePage />;
      case "classes": return <ClassesPage />;
      case "schedule": return <SchedulePage />;
      case "practice": return <PracticePage />;
      case "community": return <CommunityPage />;
      case "teachers": return <TeachersPage />;
      case "membership": return <MembershipPage />;
      case "events": return <EventsPage />;
      case "rewards": return (<div><PageHero title="NOW Points" subtitle="Earn points, unlock perks" gradient={`linear-gradient(135deg, hsl(38,50%,22%), hsl(178,25%,16%))`} /><div style={{ padding: 16 }}><div style={{ background: `linear-gradient(135deg, ${T.bg}, hsl(38,30%,18%))`, borderRadius: 16, padding: "24px 20px", color: "#fff", marginBottom: 16 }}><p style={{ fontSize: 11, fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.1em", color: T.accent, margin: "0 0 8px" }}>Your Points</p><div style={{ fontFamily: DF, fontSize: 48, fontWeight: 700 }}>1,680</div><p style={{ fontSize: 13, color: "#b8a898", margin: "4px 0 0" }}>20 points to next reward</p></div><div style={{ display: "flex", flexDirection: "column", gap: 10 }}>{[{ pts: 500, reward: "Free Guest Pass", icon: UserPlus }, { pts: 1000, reward: "Free Mat Rental (1 Month)", icon: Gift }, { pts: 1700, reward: "10% Off Workshop", icon: Award }, { pts: 2500, reward: "Scholarship Donation in Your Name", icon: Heart }].map((r, i) => (<div key={i} style={{ display: "flex", alignItems: "center", gap: 14, padding: "14px 16px", background: T.bgCard, border: `1px solid ${T.border}`, borderRadius: 12 }}><div style={{ width: 40, height: 40, borderRadius: 10, background: T.accentGhost, display: "flex", alignItems: "center", justifyContent: "center" }}><r.icon size={20} color={T.accent} /></div><div style={{ flex: 1 }}><p style={{ fontWeight: 600, fontSize: 14, margin: 0, color: T.text }}>{r.reward}</p><p style={{ fontSize: 12, color: T.textMuted, margin: "2px 0 0" }}>{r.pts} points</p></div><button style={{ padding: "6px 14px", borderRadius: 8, border: "none", fontSize: 12, fontWeight: 700, cursor: r.pts <= 1680 ? "pointer" : "default", background: r.pts <= 1680 ? T.accent : T.bgDim, color: r.pts <= 1680 ? "#fff" : T.textFaint }}>{r.pts <= 1680 ? "Redeem" : "Locked"}</button></div>))}</div></div></div>);
      case "admin-dashboard": return <AdminDashboard />;
      case "admin-members": return <AdminMembersPage />;
      case "admin-schedule": return <AdminSchedulePage />;
      case "admin-teachers": return <AdminTeachersPage />;
      case "admin-events": return <AdminEventsPage />;
      case "admin-pricing": return <AdminPricingPage />;
      case "admin-comms": return <AdminCommsPage />;
      case "admin-settings": return <AdminSettingsPage />;
      default: return <HomePage />;
    }
  };

  if (isAdmin) {
    return (<AppContext.Provider value={{ page, setPage, classRegistrations: classReg, registerForClass: regClass, openReservation: openRes, feedCelebrations: feedCel, celebrateFeed: celFeed }}>
      <div style={{ display: "flex", minHeight: "100vh", fontFamily: "'DM Sans', system-ui, sans-serif", background: "#f9fafb", color: "#111827" }}>
        <aside style={{ width: 240, background: "#ffffff", borderRight: "1px solid #e5e7eb", display: "flex", flexDirection: "column", position: "fixed", top: 0, bottom: 0 }}>
          <div style={{ padding: "16px 14px", borderBottom: "1px solid #e5e7eb", display: "flex", alignItems: "center", gap: 10 }}><div style={{ width: 36, height: 36, borderRadius: 8, background: T.accent, display: "flex", alignItems: "center", justifyContent: "center", fontFamily: DF, fontSize: 18, color: "#fff", fontWeight: 800 }}>{SC.logoMark}</div><div><span style={{ fontFamily: DF, fontSize: 16, color: "#111827", display: "block", lineHeight: 1, fontWeight: 700 }}>{SC.name}</span><span style={{ fontSize: 9, color: "#71717a", textTransform: "uppercase", letterSpacing: "0.15em" }}>Admin</span></div></div>
          <nav style={{ flex: 1, padding: "12px 8px", overflow: "auto" }}><p style={{ fontSize: 10, fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.1em", color: "#71717a", padding: "0 10px", margin: "0 0 8px" }}>Management</p>{adminTabs.map(tab => { const active = page === tab.id; return <button key={tab.id} onClick={() => setPage(tab.id)} style={{ display: "flex", alignItems: "center", gap: 10, width: "100%", padding: "10px 12px", borderRadius: 8, border: "none", background: active ? T.accent : "transparent", color: active ? "#fff" : "#6b7280", fontSize: 13, fontWeight: active ? 600 : 400, cursor: "pointer", marginBottom: 2, textAlign: "left" }}><tab.icon size={18} /><span>{tab.label}</span>{active && <ChevronRight size={14} style={{ marginLeft: "auto", opacity: 0.6 }} />}</button>; })}</nav>
          <div style={{ borderTop: "1px solid #e5e7eb", padding: "10px 8px" }}><button onClick={() => { if (onExitAdmin) { onExitAdmin(); } else { setIsAdmin(false); setPage("home"); } }} style={{ display: "flex", alignItems: "center", gap: 10, width: "100%", padding: "10px 12px", borderRadius: 8, border: "none", background: "transparent", color: "#6b7280", fontSize: 13, cursor: "pointer", textAlign: "left" }}><LogOut size={18} /><span>Exit Admin</span></button></div>
        </aside>
        <main style={{ flex: 1, marginLeft: 240, padding: 24, overflow: "auto" }}>{renderPage()}</main>
      </div>
    </AppContext.Provider>);
  }

  return (<AppContext.Provider value={{ page, setPage, classRegistrations: classReg, registerForClass: regClass, openReservation: openRes, feedCelebrations: feedCel, celebrateFeed: celFeed }}>
    <div style={{ width: "100%", height: "100%", background: T.bgDim, fontFamily: "'DM Sans', system-ui, sans-serif", position: "relative", display: "flex", flexDirection: "column", overflow: "hidden" }}>
      <header style={{ flexShrink: 0, zIndex: 30, background: T.bg, color: "#fff", padding: "10px 14px", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
        <button onClick={() => setPage("home")} style={{ display: "flex", alignItems: "center", gap: 8, background: "none", border: "none", cursor: "pointer", color: "#fff" }}>
          <div style={{ width: 38, height: 38, borderRadius: 10, background: T.accent, display: "flex", alignItems: "center", justifyContent: "center", fontFamily: DF, fontSize: 18, color: "#fff", fontWeight: 800 }}>{SC.logoMark}</div>
          <div style={{ display: "flex", flexDirection: "column" }}><span style={{ fontFamily: DF, fontSize: 20, lineHeight: 1, fontWeight: 700 }}>{SC.name}</span><span style={{ fontSize: 9, color: "#71717a", textTransform: "uppercase", letterSpacing: "0.15em" }}>{SC.subtitle}</span></div>
        </button>
        <div style={{ display: "flex", alignItems: "center", gap: 2 }}>
          <button onClick={() => { if (onEnterAdmin) { onEnterAdmin(); } else { setIsAdmin(true); setPage("admin-dashboard"); } }} style={{ padding: 8, borderRadius: 8, border: "none", background: "transparent", cursor: "pointer", color: T.accent }}><Shield size={20} /></button>
          <button onClick={() => setShowNotifications(true)} style={{ padding: 8, borderRadius: 8, border: "none", background: "transparent", cursor: "pointer", color: "#fff", position: "relative" }}><Bell size={20} /><span style={{ position: "absolute", top: 4, right: 4, width: 14, height: 14, borderRadius: "50%", background: T.accent, fontSize: 9, fontWeight: 700, display: "flex", alignItems: "center", justifyContent: "center", color: "#fff" }}>2</span></button>
          <button onClick={() => setShowSettings(true)} style={{ padding: 8, borderRadius: 8, border: "none", background: "transparent", cursor: "pointer", color: "#fff" }}><Settings size={20} /></button>
        </div>
      </header>
      <main ref={contentRef} style={{ flex: 1, overflowY: "auto", paddingBottom: 60 }}>{renderPage()}</main>
      {showMore && (<div onClick={() => setShowMore(false)} style={{ position: "absolute", inset: 0, background: "rgba(0,0,0,.5)", backdropFilter: "blur(4px)", zIndex: 40 }}><div onClick={e => e.stopPropagation()} style={{ position: "absolute", bottom: 68, left: 16, right: 16, maxWidth: 358, margin: "0 auto", background: T.bgCard, borderRadius: 16, padding: "14px 12px", boxShadow: "0 8px 32px rgba(0,0,0,.15)" }}><div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "0 6px 8px" }}><span style={{ fontFamily: DF, fontSize: 20, fontWeight: 700 }}>More</span><button onClick={() => setShowMore(false)} style={{ padding: 4, borderRadius: 6, border: "none", background: "transparent", cursor: "pointer" }}><X size={18} color={T.textMuted} /></button></div><div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8 }}>{moreItems.map(item => { const active = page === item.id; return <button key={item.id} onClick={() => { setPage(item.id); setShowMore(false); }} style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 6, padding: "14px 8px", borderRadius: 10, border: "none", cursor: "pointer", background: active ? T.accentGhost : T.bgDim, color: active ? T.accent : T.textMuted }}><item.icon size={22} /><span style={{ fontSize: 13, fontWeight: 600 }}>{item.label}</span></button>; })}</div></div></div>)}
      <nav style={{ position: "absolute", bottom: 0, left: 0, right: 0, height: 60, zIndex: 50, background: "#fff", borderTop: "1px solid #eee", display: "flex", alignItems: "center", justifyContent: "space-around" }}><div style={{ display: "flex", justifyContent: "space-around", alignItems: "center", width: "100%", height: "100%", padding: "0 4px" }}>{mainTabs.map(tab => { const active = tab.id === "more" ? (isMoreActive || showMore) : page === tab.id; return <button key={tab.id} onClick={tab.id === "more" ? () => setShowMore(true) : () => setPage(tab.id)} style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 2, padding: "6px 12px", borderRadius: 10, border: "none", background: "transparent", cursor: "pointer", color: active ? T.accent : T.textFaint }}><tab.icon size={20} strokeWidth={active ? 2.5 : 2} /><span style={{ fontSize: 10, fontWeight: active ? 700 : 500 }}>{tab.label}</span></button>; })}</div></nav>
      {showSettings && <SettingsModal onClose={() => setShowSettings(false)} />}
      {showNotifications && <NotificationsModal onClose={() => setShowNotifications(false)} />}
      {resClass && <ReservationModal classData={resClass} onConfirm={regClass} onClose={() => setResClass(null)} />}
    </div>
  </AppContext.Provider>);
}
